USE FitTrackOOP;
GO

-- Reseed identity so FoodItemId starts from 1
DBCC CHECKIDENT ('FoodItems', RESEED, 0);
GO

IF NOT EXISTS (SELECT 1 FROM FoodItems)
BEGIN
    PRINT 'Seeding 1498 FoodItems...';


    PRINT 'FoodItems seeded successfully.';
END
ELSE
BEGIN
    PRINT 'FoodItems already seeded — skipped.';
END
GO


select * from FoodItems;